package com.example.documentviewer;

import android.content.Intent;
import android.net.Uri;
import android.os.Bundle;
import android.widget.Toast;
import androidx.appcompat.app.AppCompatActivity;
import java.io.File;

public class DocumentViewerActivity extends AppCompatActivity {
    
    @Override
    protected void onCreate(Bundle savedInstanceState) {
        super.onCreate(savedInstanceState);
        setContentView(R.layout.activity_document_viewer);
        
        Intent intent = getIntent();
        String action = intent.getAction();
        String type = intent.getType();
        
        if (Intent.ACTION_VIEW.equals(action) && type != null) {
            Uri uri = intent.getData();
            if (uri != null) {
                String filePath = getFilePathFromUri(uri);
                if (filePath != null) {
                    displayDocument(filePath);
                } else {
                    Toast.makeText(this, "Unable to open document", Toast.LENGTH_SHORT).show();
                    finish();
                }
            } else {
                Toast.makeText(this, "Invalid file URI", Toast.LENGTH_SHORT).show();
                finish();
            }
        } else {
            Toast.makeText(this, "Invalid intent", Toast.LENGTH_SHORT).show();
            finish();
        }
    }
    
    private String getFilePathFromUri(Uri uri) {
        String filePath = null;
        try {
            if (uri.getScheme().equals("content")) {
                filePath = uri.getPath();
            } else if (uri.getScheme().equals("file")) {
                filePath = uri.getPath();
            }
        } catch (Exception e) {
            e.printStackTrace();
        }
        return filePath;
    }
    
    private void displayDocument(String filePath) {
        File file = new File(filePath);
        if (file.exists()) {
            // Handle PDF and image files
            String fileExtension = getFileExtension(filePath);
            if (fileExtension != null) {
                if (fileExtension.equals("pdf")) {
                    // Handle PDF display
                    // Implement PDF rendering logic here
                } else if (fileExtension.equals("jpg") || fileExtension.equals("jpeg") || 
                          fileExtension.equals("png") || fileExtension.equals("gif")) {
                    // Handle image display
                    // Implement image rendering logic here
                }
            }
        } else {
            Toast.makeText(this, "File not found", Toast.LENGTH_SHORT).show();
        }
    }
    
    private String getFileExtension(String filePath) {
        int dotIndex = filePath.lastIndexOf('.');
        if (dotIndex > 0) {
            return filePath.substring(dotIndex + 1).toLowerCase();
        }
        return null;
    }
}